def sift_up(heap, i):
    """Bubble element at index i upward until heap property is restored."""
    while i > 0:
        parent = (i - 1) // 2
        if heap[parent] > heap[i]:
            heap[parent], heap[i] = ___________
            i = parent
        else:
            break

def heap_push(heap, val):
    heap.append(val)
    sift_up(heap, len(heap) - 1)
    return heap
